const fs = require('fs');
const path = require('path');

const jobId = $('Extract Fields').item.json.job_id;
const scriptText = $('Extract Fields').item.json.script_text;
const channelId = $('Extract Fields').item.json.channel_id;
const userId = $('Extract Fields').item.json.user_id;
const autoTrigger = !!$('Extract Fields').item.json.auto_trigger_wf12;

if (!scriptText || !scriptText.trim()) {
  return {
    json: {
      ok: false,
      error: 'script_text is required',
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
}

try {
  const ttsBody = {
    text: scriptText,
    text_lang: $env.TTS_TEXT_LANG || 'ko',
    media_type: 'wav',
    streaming_mode: false,
  };

  const hasRefAudio = !!($env.TTS_REF_AUDIO_PATH || '').trim();
  const hasRefText = !!($env.TTS_PROMPT_TEXT || '').trim();

  // 음색 클론을 쓸 때만 ref 오디오/텍스트를 함께 전달한다.
  if (hasRefAudio || hasRefText) {
    if (!(hasRefAudio && hasRefText)) {
      throw new Error('TTS_REF_AUDIO_PATH와 TTS_PROMPT_TEXT는 함께 설정해야 합니다.');
    }
    ttsBody.ref_audio_path = $env.TTS_REF_AUDIO_PATH;
    ttsBody.prompt_text = $env.TTS_PROMPT_TEXT;
    ttsBody.prompt_lang = $env.TTS_PROMPT_LANG || 'ko';
  }

  const ttsResp = await fetch(`${$env.TTS_API_URL}/tts`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(ttsBody),
  });

  if (!ttsResp.ok) {
    throw new Error(`TTS API failed: ${ttsResp.status} ${await ttsResp.text()}`);
  }

  const audioBuffer = await ttsResp.arrayBuffer();
  const audioBytes = Buffer.from(audioBuffer);
  const audioB64 = audioBytes.toString('base64');

  const now = new Date();
  const ts = `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}_${String(now.getHours()).padStart(2, '0')}${String(now.getMinutes()).padStart(2, '0')}${String(now.getSeconds()).padStart(2, '0')}`;
  const filename = `tts_${jobId.substring(0, 8)}_${ts}.wav`;

  const dir = '/home/node/.n8n/audio';
  fs.mkdirSync(dir, { recursive: true });
  const filePath = path.join(dir, filename);
  fs.writeFileSync(filePath, audioBytes);

  return {
    json: {
      ok: true,
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
      script_text: scriptText,
      audio_file_path: filePath,
      filename,
      audio_content_b64: audioB64,
      auto_trigger_wf12: autoTrigger,
    },
  };
} catch (e) {
  const message = e && e.message ? e.message : String(e);
  return {
    json: {
      ok: false,
      error: message,
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
}
